import React, {useState} from 'react'
import ReactPlayer from "react-player";
import ScrollAnimation from "react-animate-on-scroll";
const Projects = () => {
    const [isShown, SetIsShown] = useState(0);
    const [isPlayable,SetPlayable] = useState(0);
    return(
        <div className="ui center aligned segment">
            <div className="grid">
                <div className="cell"
                     onMouseEnter={() => (SetIsShown(1),SetPlayable(1))}
                     onMouseLeave={() => (SetIsShown(0),SetPlayable(0))}
                     onClick={()=>(SetIsShown(1),SetPlayable(1))}
                >
                    <div>
                        <button
                            className="ui orange inverted button demo1"
                            style={{opacity:isShown===1 ? 1:0,transition: "opacity 1s"}}>Learn More</button>
                    </div>
                    <ReactPlayer
                        url="./videos/Helicopter_Demo.MP4"
                        width='40vw'
                        height='40vh'
                        volume={1}
                        muted={true}
                        loop={true}
                        playing={isPlayable===1 ? 0:1}
                        // controls={isPlayable==1 ? 0 : 1}
                        controls={true}
                    ></ReactPlayer>
                </div>
                <div className="cell"
                     onMouseEnter={() => (SetIsShown(2),SetPlayable(2))}
                     onMouseLeave={() => (SetIsShown(0),SetPlayable(0))}
                >
                    <div>
                        <button
                            className="ui orange inverted button demo2"
                            style={{opacity:isShown===2 ? 2:0,transition: "opacity 1s"}}>Learn More</button>
                    </div>
                    <ReactPlayer
                        url="./videos/Solar_System_Demo.MP4"
                        width='40vw'
                        height='40vh'
                        volume={1}
                        muted={true}
                        loop={true}
                        playing={isPlayable===2 ? 0:2}
                        controls={true}
                    ></ReactPlayer>
                </div>
            </div>
        </div>
    );
};
export default Projects;
